use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize, Debug, Clone)]
#[serde(tag = "kind")]
pub enum BridgeExpression {
    #[serde(rename = "input")]
    Input { #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
    #[serde(rename = "binding")]
    Binding { name: String, #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
    #[serde(rename = "runtime")]
    Runtime { name: String, #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
    #[serde(rename = "literal")]
    Literal { value: serde_json::Value, #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
    #[serde(rename = "member")]
    Member {
        target: Box<BridgeExpression>,
        property: String,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "index")]
    Index {
        target: Box<BridgeExpression>,
        index: serde_json::Value, // string or number
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "array")]
    Array { items: Vec<BridgeExpression>, #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
    #[serde(rename = "object")]
    Object { entries: Vec<BridgeObjectEntry>, #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value> },
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct BridgeObjectEntry {
    pub key: String,
    pub value: BridgeExpression,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct SourceLocation {
    pub line: u32,
    pub column: u32,
    #[serde(rename = "endLine")]
    pub end_line: Option<u32>,
    #[serde(rename = "endColumn")]
    pub end_column: Option<u32>,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
#[serde(tag = "kind")]
pub enum BridgeNodePlan {
    #[serde(rename = "entry")]
    Entry {
        #[serde(rename = "nodeId")]
        node_id: String,
        #[serde(rename = "handlerLabel")]
        handler_label: String, // "TsBridgeEntry"
        #[serde(rename = "sourceLocation")]
        source_location: Option<SourceLocation>,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "assign")]
    Assign {
        #[serde(rename = "nodeId")]
        node_id: String,
        #[serde(rename = "handlerLabel")]
        handler_label: String, // "TsBridgeAssign"
        #[serde(rename = "bindingName")]
        binding_name: String,
        expression: BridgeExpression,
        #[serde(rename = "sourceLocation")]
        source_location: Option<SourceLocation>,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "call")]
    Call {
        #[serde(rename = "nodeId")]
        node_id: String,
        #[serde(rename = "handlerLabel")]
        handler_label: String, // "TsBridgeCall"
        callee: BridgeExpression,
        #[serde(rename = "thisArg")]
        this_arg: Option<BridgeExpression>,
        args: Vec<BridgeExpression>,
        #[serde(rename = "assignTo")]
        assign_to: Option<String>,
        #[serde(rename = "sourceLocation")]
        source_location: Option<SourceLocation>,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "join")]
    Join {
        #[serde(rename = "nodeId")]
        node_id: String,
        #[serde(rename = "handlerLabel")]
        handler_label: String, // "TsBridgeJoin"
        #[serde(rename = "sourceLocation")]
        source_location: Option<SourceLocation>,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
    #[serde(rename = "return")]
    Return {
        #[serde(rename = "nodeId")]
        node_id: String,
        #[serde(rename = "handlerLabel")]
        handler_label: String, // "TsBridgeReturn"
        expression: BridgeExpression,
        #[serde(rename = "sourceLocation")]
        source_location: Option<SourceLocation>,
        #[serde(default, skip_serializing_if = "Option::is_none")] ghost_mass: Option<serde_json::Value>,
    },
}

impl BridgeNodePlan {
    pub fn node_id(&self) -> &str {
        match self {
            BridgeNodePlan::Entry { node_id, .. } => node_id,
            BridgeNodePlan::Assign { node_id, .. } => node_id,
            BridgeNodePlan::Call { node_id, .. } => node_id,
            BridgeNodePlan::Join { node_id, .. } => node_id,
            BridgeNodePlan::Return { node_id, .. } => node_id,
        }
    }

    pub fn handler_label(&self) -> &str {
        match self {
            BridgeNodePlan::Entry { handler_label, .. } => handler_label,
            BridgeNodePlan::Assign { handler_label, .. } => handler_label,
            BridgeNodePlan::Call { handler_label, .. } => handler_label,
            BridgeNodePlan::Join { handler_label, .. } => handler_label,
            BridgeNodePlan::Return { handler_label, .. } => handler_label,
        }
    }
}

#[derive(Serialize, Deserialize, Debug, Clone)]
#[serde(tag = "kind")]
pub enum BridgeOperation {
    #[serde(rename = "assign")]
    Assign {
        plan: BridgeNodePlan, // Must be Assign variant
    },
    #[serde(rename = "call")]
    Call {
        plan: BridgeNodePlan, // Must be Call variant
    },
    #[serde(rename = "return")]
    Return {
        plan: BridgeNodePlan, // Must be Return variant
    },
    #[serde(rename = "parallel")]
    Parallel {
        branches: Vec<BridgeNodePlan>, // Must be Call variants
        #[serde(rename = "joinPlan")]
        join_plan: BridgeNodePlan, // Must be Join variant
    },
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct BridgeWave {
    pub index: u32,
    pub kind: String, // "linear" | "parallel" | "collapse"
    #[serde(rename = "nodeIds")]
    pub node_ids: Vec<String>,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct ASTNode {
    pub id: String,
    pub labels: Vec<String>,
    pub properties: serde_json::Value,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct ASTEdge {
    #[serde(rename = "sourceIds")]
    pub source_ids: Vec<String>,
    #[serde(rename = "targetIds")]
    pub target_ids: Vec<String>,
    pub r#type: String,
    pub properties: serde_json::Value,
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct GraphAST {
    pub nodes: Vec<ASTNode>,
    pub edges: Vec<ASTEdge>,
}
